CREATE OR REPLACE FUNCTION OFSERM.BANKING_LEASE_RESIDUAL_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_CREDIT_LINE_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_GUARANTEE_SCHEME_SKEY,N_ISSUE_SKEY,F_CORE_INVESTMENT_COMPANY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,N_REG_CAP_GUARANTEE_SCH_SKEY,N_REPAYMENT_TYPE_SKEY,F_EXP_FUND_CCY_SAME_IND,F_LEASE_RESIDUAL_INDICATOR,N_CURR_12M_ECL,N_EFF_MATURITY,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_GENERAL_PROVISION_AMT,N_LOSS_ALLOWANCE_LIFE_ECL,N_ORIGINAL_MATURITY,N_PARENT_ACCT_SKEY,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_SANCTIONED_LIMIT,N_SHAREHOLDING_PERCENT,V_DATA_SOURCE,V_EXP_RCY_CODE,N_ENTITY_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_EXP_PRIORITY_SECTOR,F_EXP_TREATED_AS_HIGH_RISK,F_FINANCIAL_ASSET_IFRS9_FLAG,N_CCF_OWN_ESTIMATE,N_CCF_OWN_ESTIMATE_DRAWN,N_DVA_AMOUNT,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_TXN_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_RUN_PARAMETER_SETUP_SKEY,D_EXPOSURE_START_DATE,D_EXPOSURE_END_DATE,F_EXP_DEFAULTED_FLAG,F_PAST_DUE_FLAG,F_RESTRUCTURED_IND,F_EXP_REV_FLAG,F_SECURITIZED_FLAG,N_DELQ_DAYS,N_LOAD_RUN_ID,N_RESIDUAL_VALUE,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_CREDIT_LINE.N_CREDIT_LINE_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_GUARANTEE_SCHEME.N_GUARANTEE_SCHEME_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),to_char(DIM_REG_CAP_GUARANTEE_SCHEME.N_REG_CAP_GUARANTEE_SCH_SKEY),to_char(DIM_REPAYMENT_TYPE.N_REPAYMENT_TYPE_SKEY),CASE WHEN DIM_COUNTRY.V_CURRENCY_CODE=STG_LEASES_CONTRACTS.V_CCY_CODE THEN 'Y' ELSE 'N' END,'Y',CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,CASE  WHEN COALESCE(STG_LEASES_CONTRACTS.F_REVOLVE_IND, 'N') = 'Y' THEN DAYS_BETWEEN(STG_LEASES_CONTRACTS.FIC_MIS_DATE, STG_LEASES_CONTRACTS.D_EFF_MATURITY_DATE) ELSE COALESCE(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY, DAYS_BETWEEN(STG_LEASES_CONTRACTS.FIC_MIS_DATE, STG_LEASES_CONTRACTS.D_MATURITY_DATE, STG_LEASES_CONTRACTS.V_DAY_COUNT_IND)) END,STG_LEASES_CONTRACTS.N_GUARANTEED_AMT,STG_LEASES_CONTRACTS.N_GUARANTEED_RESIDUAL_AMT,FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,DAYS_BETWEEN(STG_LEASES_CONTRACTS.D_LEASE_START_DATE,STG_LEASES_CONTRACTS.D_MATURITY_DATE,STG_LEASES_CONTRACTS.V_DAY_COUNT_IND),DIM_PARENT_EXPOSURE.N_ACCT_SKEY,DAYS_BETWEEN(STG_LEASES_CONTRACTS.FIC_MIS_DATE, STG_LEASES_CONTRACTS.D_MATURITY_DATE,STG_LEASES_CONTRACTS.V_DAY_COUNT_IND),'870',(STG_LEASES_CONTRACTS.N_SANCTIONED_LIMIT * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE),CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,'STG_LEASES_CONTRACTS',RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_PRIORITY_SECTOR,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE_DRAWN),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_TXN_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY),STG_LEASES_CONTRACTS.D_LEASE_START_DATE,STG_LEASES_CONTRACTS.D_MATURITY_DATE,STG_LEASES_CONTRACTS.F_EXP_DEFAULTED_FLAG,STG_LEASES_CONTRACTS.F_PAST_DUE_FLAG,STG_LEASES_CONTRACTS.F_RESTRUCTURED_IND,STG_LEASES_CONTRACTS.F_REVOLVE_IND,STG_LEASES_CONTRACTS.F_SECURITIZED_FLAG,to_char(STG_LEASES_CONTRACTS.N_DELINQUENT_DAYS),to_char(STG_LEASES_CONTRACTS.N_LOAD_RUN_ID),to_char(STG_LEASES_CONTRACTS.N_RESIDUAL_AMOUNT),STG_LEASES_CONTRACTS.V_CCY_CODE FROM STG_LEASES_CONTRACTS INNER JOIN DIM_DATES ON STG_LEASES_CONTRACTS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(STG_LEASES_CONTRACTS.F_SECURITIZED_FLAG, 'N') <> 'Y' AND STG_LEASES_CONTRACTS.D_ACCT_CLOSED_DATE >= STG_LEASES_CONTRACTS.FIC_MIS_DATE INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_EXPOSURE ON STG_LEASES_CONTRACTS.V_ACCOUNT_NUMBER || '_RESIDUAL' = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.d_record_start_date AND DIM_EXPOSURE.d_record_end_date INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.n_run_skey = '870' AND STG_LEASES_CONTRACTS.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND COALESCE(FCT_ENTITY_INFO.f_cap_consl_entity_ind, 'N') = 'Y' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code IN ( 'FLCS' ,'PRCS' ) LEFT OUTER JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_LEASES_CONTRACTS.V_ACCOUNT_NUMBER = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARENT_EXPOSURE.d_record_start_date AND DIM_PARENT_EXPOSURE.d_record_end_date LEFT OUTER JOIN DIM_PARTY ON COALESCE(STG_LEASES_CONTRACTS.V_CUST_REF_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.d_record_start_date AND DIM_PARTY.d_record_end_date LEFT OUTER JOIN DIM_PRODUCT ON STG_LEASES_CONTRACTS.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.d_record_start_date AND DIM_PRODUCT.d_record_end_date LEFT OUTER JOIN DIM_LOB ON STG_LEASES_CONTRACTS.V_LINE_CODE = DIM_LOB.V_LOB_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.d_record_start_date AND DIM_LOB.d_record_end_date LEFT OUTER JOIN DIM_GEOGRAPHY ON STG_LEASES_CONTRACTS.V_BRANCH_CODE = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.d_record_start_date AND DIM_GEOGRAPHY.d_record_end_date LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = DIM_PARTY.V_INDUSTRY_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.d_record_start_date AND DIM_INDUSTRY.d_record_end_date LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_LEASES_CONTRACTS.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID = COALESCE(STG_LEASES_CONTRACTS.V_COUNTRY_ID, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.d_record_start_date AND DIM_COUNTRY.d_record_end_date LEFT OUTER JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ISSUE ON COALESCE(STG_LEASES_CONTRACTS.v_account_number, DIM_EXPOSURE.V_EXPOSURE_ID) = DIM_ISSUE.v_issue_code AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.d_record_start_date AND DIM_ISSUE.d_record_end_date INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.d_record_start_date AND DIM_PARTY_TYPE.d_record_end_date LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_LEASES_CONTRACTS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' LEFT OUTER JOIN DIM_GUARANTEE_SCHEME ON DIM_GUARANTEE_SCHEME.V_GUARANTEE_SCHEME_CODE = STG_LEASES_CONTRACTS.V_GUARANTEE_SCHEME_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GUARANTEE_SCHEME.D_RECORD_START_DATE AND DIM_GUARANTEE_SCHEME.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_GUAR_SCHEME_RECLASS ON FSI_CAP_GUAR_SCHEME_RECLASS.N_GUARANTEE_SCHEME_SKEY = DIM_GUARANTEE_SCHEME.N_GUARANTEE_SCHEME_SKEY AND FSI_CAP_GUAR_SCHEME_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_REG_CAP_GUARANTEE_SCHEME ON DIM_REG_CAP_GUARANTEE_SCHEME.N_REG_CAP_GUARANTEE_SCH_SKEY = FSI_CAP_GUAR_SCHEME_RECLASS.N_REG_CAP_GUARANTEE_SCH_SKEY AND to_date('20260331','YYYYMMDD') BETWEEN DIM_REG_CAP_GUARANTEE_SCHEME.D_RECORD_START_DATE AND DIM_REG_CAP_GUARANTEE_SCHEME.D_RECORD_END_DATE LEFT OUTER JOIN DIM_REPAYMENT_TYPE ON DIM_REPAYMENT_TYPE.V_REPAYMENT_TYPE = STG_LEASES_CONTRACTS.V_REPAYMENT_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_REPAYMENT_TYPE.D_RECORD_START_DATE AND DIM_REPAYMENT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = '870' AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT JOIN FSI_CAP_ACCOUNT_PORTFOLIO_MAP ON FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_RUN_SKEY = '870' AND FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_CAP_APPROACH_TYPE_SKEY AND DIM_EXPOSURE.V_EXPOSURE_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_ACCOUNT_NUMBER AND DIM_GAAP.V_GAAP_CODE = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_PORTFOLIO_MAP.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND STG_LEASES_CONTRACTS.N_LOAD_RUN_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_LOAD_RUN_ID LEFT OUTER JOIN DIM_CREDIT_LINE ON STG_LEASES_CONTRACTS.V_LINE_CODE = DIM_CREDIT_LINE.V_CREDIT_LINE_CODE AND DIM_DATES.D_CALENDAR_DATE BETWEEN DIM_CREDIT_LINE.D_RECORD_START_DATE AND DIM_CREDIT_LINE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PROD_TXN_TYPE_RECLASS ON FSI_PROD_TXN_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY = DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY AND FSI_PROD_TXN_TYPE_RECLASS.N_RUN_SKEY = '870' WHERE 1=1 AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = DIM_EXPOSURE.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_LEASES_CONTRACTS.N_LOAD_RUN_ID ) AND DAYS_BETWEEN(STG_LEASES_CONTRACTS.FIC_MIS_DATE, STG_LEASES_CONTRACTS.D_MATURITY_DATE, STG_LEASES_CONTRACTS.V_DAY_COUNT_IND) > 0 AND 1 = CASE WHEN (FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG = 'N') OR ( FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG = 'Y' AND FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_PORTFOLIO_SKEY IS NOT NULL ) THEN 1 ELSE 2 END LOG ERRORS INTO FSI_CAP_BANKING_EXPOSURES$ ('1776768365421_70563835_20260331_1_Job_1588064551504') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
